import React, {useState} from "react";

function CssMenu() {
    const [gridType, setGridType] = useState("flex");

    return (
        <div className="CssMenu">
            <form>
                <label for="input1">Input 1</label>
                <input name="input1" type="text" placeholder="Input 1"></input>
            </form>
        </div>
    )
} 

export default CssMenu;
